+export function applyContextPruningDefaults(
+  cfg: ClawdbotConfig,
+): ClawdbotConfig {
+  const agent = cfg.agent;
+  const contextPruning = agent?.contextPruning;
+  if (contextPruning?.mode) return cfg;
+
+  return {
+    ...cfg,
+    agent: {
+      ...agent,
+      contextPruning: {
+        ...contextPruning,
+        mode: "adaptive",
+      },
+    },
+  };
+}
